import { app, BrowserWindow, session, ipcMain, dialog } from 'electron';
import * as path from 'path';

let mainWindow: BrowserWindow | null = null;

async function createWindow() {
    // Set security policies with expanded CSP
    session.defaultSession.webRequest.onHeadersReceived((details, callback) => {
        callback({
            responseHeaders: {
                ...details.responseHeaders,
                'Content-Security-Policy': [
                    "default-src 'self' 'unsafe-inline' 'unsafe-eval' data: chrome-extension: file: http://localhost:* http://127.0.0.1:*;" +
                    "img-src 'self' data: https: file: chrome-extension: http://localhost:* http://127.0.0.1:*;" +
                    "script-src 'self' 'unsafe-inline' 'unsafe-eval' http://localhost:* http://127.0.0.1:*;" +
                    "style-src 'self' 'unsafe-inline' http://localhost:* http://127.0.0.1:*;" +
                    "connect-src 'self' ws: wss: http: https: chrome-extension: file: data: http://localhost:* http://127.0.0.1:*"
                ]
            }
        });
    });

    mainWindow = new BrowserWindow({
        width: 1200,
        height: 800,
        webPreferences: {
            nodeIntegration: false,
            contextIsolation: true,
            sandbox: false,
            webSecurity: true,
            preload: path.join(__dirname, 'preload.js')
        }
    });

    if (process.env.NODE_ENV === 'development') {
        try {
            await mainWindow.loadURL('http://localhost:3000');
            mainWindow.webContents.openDevTools();
        } catch {
            try {
                await mainWindow.loadURL('http://localhost:3001');
                mainWindow.webContents.openDevTools();
            } catch (error) {
                console.error('Failed to connect to development server:', error);
            }
        }
    } else {
        await mainWindow.loadFile(path.join(__dirname, '../out/index.html'));
    }

    mainWindow.on('closed', () => {
        mainWindow = null;
    });
}

app.whenReady().then(createWindow);

ipcMain.handle('select-directory', async () => {
    const result = await dialog.showOpenDialog({
        properties: ['openDirectory'],
        title: 'Select Artifacts Directory',
        buttonLabel: 'Select Folder'
    });

    if (result.canceled) {
        return null;
    }
    return result.filePaths[0];
});

app.on('window-all-closed', () => {
    if (process.platform !== 'darwin') {
        app.quit();
    }
});

app.on('activate', () => {
    if (mainWindow === null) {
        createWindow();
    }
});

import { contextBridge, ipcRenderer } from 'electron';
import * as fs from 'fs/promises';
import * as path from 'path';

// Define valid encoding types
type ValidEncoding = 'utf8' | 'utf-8' | 'ascii' | 'utf16le' | 'ucs2' | 'ucs-2' | 'base64' | 'base64url' | 'latin1' | 'binary' | 'hex';

// Expose protected methods that allow the renderer process to use
// the ipcRenderer without exposing the entire object
contextBridge.exposeInMainWorld(
    'electron',
    {
        ipcRenderer: {
            send: (channel: string, data: any) => {
                ipcRenderer.send(channel, data);
            },
            on: (channel: string, func: (...args: any[]) => void) => {
                ipcRenderer.on(channel, (event, ...args) => func(...args));
            },
            invoke: (channel: string, ...args: any[]) => {
                return ipcRenderer.invoke(channel, ...args);
            }
        }
    }
);

// Expose file system methods
contextBridge.exposeInMainWorld(
    'fs',
    {
        readdir: async (dir: string) => {
            try {
                const artifactsPath = path.isAbsolute(dir) ? dir : path.join(process.cwd(), dir);
                return await fs.readdir(artifactsPath);
            } catch (error) {
                console.error('Error reading directory:', error);
                throw error;
            }
        },
        readFile: async (filePath: string, options?: { encoding?: ValidEncoding }) => {
            try {
                const fullPath = path.isAbsolute(filePath) ? filePath : path.join(process.cwd(), filePath);
                if (options?.encoding) {
                    return await fs.readFile(fullPath, { 
                        encoding: options.encoding as BufferEncoding 
                    });
                }
                return await fs.readFile(fullPath);
            } catch (error) {
                console.error('Error reading file:', error);
                throw error;
            }
        },
        writeFile: async (filePath: string, data: string) => {
            try {
                const fullPath = path.isAbsolute(filePath) ? filePath : path.join(process.cwd(), filePath);
                await fs.writeFile(fullPath, data);
            } catch (error) {
                console.error('Error writing file:', error);
                throw error;
            }
        },
        mkdir: async (dirPath: string, options?: { recursive?: boolean }) => {
            try {
                const fullPath = path.isAbsolute(dirPath) ? dirPath : path.join(process.cwd(), dirPath);
                await fs.mkdir(fullPath, options);
            } catch (error) {
                console.error('Error creating directory:', error);
                throw error;
            }
        }
    }
);

