'use client';

import React, { useState, useEffect } from 'react';
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Folder } from "lucide-react";
import { DynamicArtifact } from "@/components/DynamicArtifact";
import { ArtifactRunner } from "@/components/ArtifactRunner";

interface PageFile {
    name: string;
    content: React.ComponentType<{ className?: string }>;
}

const DynamicPageSwitcher: React.FC = () => {
    const [pages, setPages] = useState<PageFile[]>([]);
    const [currentPage, setCurrentPage] = useState<string>('');
    const [error, setError] = useState<string>('');
    const [bgColor] = useState<string>('bg-gray-900');
    const [isLoading, setIsLoading] = useState(false);
    const [artifactsPath, setArtifactsPath] = useState<string>('');

    const selectDirectory = async () => {
        try {
            if (typeof window === 'undefined' || !window.electron) {
                throw new Error('Electron API not available');
            }

            setIsLoading(true);
            const selectedPath = await window.electron.ipcRenderer.invoke('select-directory');

            if (selectedPath) {
                setArtifactsPath(selectedPath);
                await loadPages(selectedPath);
            } else {
                // User cancelled the dialog
                setIsLoading(false);
            }
        } catch (error) {
            const errorMessage = error instanceof Error ? error.message : 'Failed to select directory';
            setError(errorMessage);
            console.error('Error selecting directory:', error);
            setIsLoading(false);
        }
    };

    const loadPages = async (dirPath: string) => {
        try {
            setIsLoading(true);
            setError('');

            if (typeof window === 'undefined' || !window.fs) {
                throw new Error('File system API not available');
            }

            const artifactsContent = await window.fs.readdir(dirPath);
            const tsxFiles = artifactsContent.filter(file => 
                file.endsWith('.tsx') || file.endsWith('.ts')
            );

            if (tsxFiles.length === 0) {
                setError('No artifacts found in the selected folder');
                setPages([]);
                setIsLoading(false);
                return;
            }

            // Load the content of each file
            const loadedPages = await Promise.all(
                tsxFiles.map(async (file) => {
                    try {
                        const filePath = `${dirPath}/${file}`;
                        const content = await window.fs.readFile(filePath, { encoding: 'utf8' }) as string;

                        return {
                            name: file.replace(/\.[^/.]+$/, ''),
                            content: content,
                            filePath: filePath
                        };
                    } catch (err) {
                        console.error(`Error loading ${file}:`, err);
                        return null;
                    }
                })
            );

            const validPages = loadedPages.filter((page): page is { name: string; content: string; filePath: string } => page !== null);
            setPages(validPages);

            if (validPages.length > 0) {
                setCurrentPage(validPages[0].name);
            }
        } catch (error) {
            const errorMessage = error instanceof Error ? error.message : 'Failed to load artifacts';
            setError(errorMessage);
            console.error('Error loading pages:', error);
        } finally {
            setIsLoading(false);
        }
    };

    const [viewMode, setViewMode] = useState<'code' | 'execute'>('code');

    const renderCurrentPage = () => {
        const page = pages.find(p => p.name === currentPage);
        if (!page) return null;

        return (
          <div className="w-full h-full">
            <h2 className="text-xl font-bold mb-4">{page.name}</h2>

            {/* Toggle button to switch between code view and execution */}
            <div className="mb-4">
              <button 
                onClick={() => setViewMode(viewMode === 'code' ? 'execute' : 'code')}
                className="px-4 py-2 bg-blue-500 text-white rounded hover:bg-blue-600"
              >
                {viewMode === 'code' ? 'Execute Artifact' : 'View Code'}
              </button>
            </div>

            {viewMode === 'code' ? (
              <DynamicArtifact filePath={page.filePath} className={bgColor} />
            ) : (
              <ArtifactRunner filePath={page.filePath} className={bgColor} />
            )}
          </div>
        );
      };

    const CodeViewer = ({ filePath }) => {
        const [content, setContent] = useState<string>('');
        const [error, setError] = useState<string>('');

        useEffect(() => {
            async function loadContent() {
                try {
                    const fileContent = await window.fs.readFile(filePath, { encoding: 'utf8' });
                    setContent(fileContent as string);
                } catch (err) {
                    setError(`Failed to load file: ${err.message}`);
                }
            }

            loadContent();
        }, [filePath]);

        if (error) return <div className="text-red-600">{error}</div>;

        return (
            <pre className="bg-gray-100 p-4 rounded overflow-auto max-h-[600px]">
                <code>{content}</code>
            </pre>
        );
    };

    if (isLoading) {
        return (
            <div className="flex items-center justify-center min-h-screen">
                <div className="animate-spin rounded-full h-8 w-8 border-t-2 border-b-2 border-blue-500"></div>
            </div>
        );
    }

    if (!artifactsPath) {
        return (
            <div className="flex items-center justify-center min-h-screen bg-gray-100">
                <Card className="w-96">
                    <CardHeader>
                        <CardTitle>Select Artifacts Directory</CardTitle>
                        <CardDescription>
                            Please select a folder containing your artifact files (.tsx/.ts)
                        </CardDescription>
                    </CardHeader>
                    <CardContent>
                        <Button 
                            onClick={selectDirectory} 
                            className="w-full flex items-center justify-center gap-2"
                        >
                            <Folder className="h-5 w-5" />
                            Select Folder
                        </Button>
                        {error && (
                            <div className="mt-4 text-red-600">
                                Error: {error}
                            </div>
                        )}
                    </CardContent>
                </Card>
            </div>
        );
    }

    return (
        <div className="flex min-h-screen">
            <div className="w-64 bg-gray-100 p-4">
                <div className="mb-4">
                    <Button 
                        onClick={selectDirectory} 
                        variant="outline" 
                        className="w-full flex items-center justify-center gap-2"
                    >
                        <Folder className="h-4 w-4" />
                        Change Folder
                    </Button>
                </div>
                <h2 className="text-xl font-bold mb-4">Artifacts</h2>
                <nav className="space-y-2">
                    {pages.map((page) => (
                        <button
                            key={page.name}
                            onClick={() => setCurrentPage(page.name)}
                            className={`w-full text-left px-4 py-2 rounded ${
                                currentPage === page.name 
                                    ? 'bg-blue-500 text-white' 
                                    : 'hover:bg-gray-200'
                            }`}
                        >
                            {page.name}
                        </button>
                    ))}
                    {pages.length === 0 && !error && (
                        <p className="text-gray-500 p-4">No artifacts found</p>
                    )}
                </nav>
            </div>

            <div className="flex-1 p-8">
                {error ? (
                    <div className="p-4 text-red-600">
                        Error: {error}
                    </div>
                ) : (
                    renderCurrentPage()
                )}
            </div>
        </div>
    );
};

export default DynamicPageSwitcher;

