'use client';

import React, { useState, useEffect, useRef } from 'react';
import { Card, CardContent } from '@/components/ui/card';

interface ArtifactRunnerProps {
  filePath: string;
  className?: string;
}

export const ArtifactRunner: React.FC<ArtifactRunnerProps> = ({ filePath, className }) => {
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [artifactHtml, setArtifactHtml] = useState<string>('');

  useEffect(() => {
    const prepareArtifact = async () => {
      try {
        setIsLoading(true);

        // Get the file content
        const fileContent = await window.fs.readFile(filePath, { encoding: 'utf8' }) as string;

        // Create a basic HTML template
        const html = `
          <!DOCTYPE html>
          <html>
          <head>
            <meta charset="UTF-8">
            <meta name="viewport" content="width=device-width, initial-scale=1.0">
            <meta http-equiv="Content-Security-Policy" content="default-src 'self' 'unsafe-inline' 'unsafe-eval' https:; style-src 'self' 'unsafe-inline' https:;">
            <title>Artifact Runner</title>
            <script src="https://unpkg.com/react@18/umd/react.development.js"></script>
            <script src="https://unpkg.com/react-dom@18/umd/react-dom.development.js"></script>
            <script src="https://unpkg.com/babel-standalone@6/babel.min.js"></script>
            <link href="https://cdn.jsdelivr.net/npm/tailwindcss@2.2.19/dist/tailwind.min.css" rel="stylesheet">
            <style>
              body { font-family: sans-serif; padding: 0; margin: 0; }
              #root { width: 100%; height: 100vh; }
            </style>
          </head>
          <body>
            <div id="root"></div>
            <script type="text/babel">
              // Make dependencies available globally
              const { useState, useEffect, useRef } = React;

              // Mock components
              const mockComponent = (props) => React.createElement('div', props, props.children);
              const Card = mockComponent;
              const CardContent = mockComponent;

              // Artifact code
              ${fileContent.replace(/import\s+.*?from\s+['"].*?['"]/g, '// $&')}

              // Render
              const rootElement = document.getElementById('root');
              const Artifact = Game || default;
              ReactDOM.render(React.createElement(Artifact, {}), rootElement);
            </script>
          </body>
          </html>
        `;

        setArtifactHtml(html);
        setIsLoading(false);
      } catch (err) {
        console.error('Error preparing artifact:', err);
        setError(`Error preparing artifact: ${err instanceof Error ? err.message : String(err)}`);
        setIsLoading(false);
      }
    };

    prepareArtifact();
  }, [filePath]);

  if (isLoading) {
    return (
      <Card className={`w-full h-full ${className}`}>
        <CardContent className="p-4 flex items-center justify-center">
          <div className="animate-pulse text-center">
            <p>Loading artifact...</p>
          </div>
        </CardContent>
      </Card>
    );
  }

  if (error) {
    return (
      <Card className={`w-full h-full ${className}`}>
        <CardContent className="p-4">
          <div className="bg-red-100 p-4 rounded border border-red-400 text-red-700">
            <h3 className="font-bold">Error</h3>
            <pre className="mt-2 overflow-auto max-h-64">{error}</pre>
          </div>
        </CardContent>
      </Card>
    );
  }

  // Note: You'll need to enable webview tag in your Electron config
  return (
    <div className={`w-full h-full ${className}`}>
      <webview
        srcDoc={artifactHtml}
        className="w-full h-full border-0"
        nodeintegration="true"
        webpreferences="allowRunningInsecureContent=yes"
      />
    </div>
  );
};

'use client';

import React, { useState, useEffect } from 'react';

interface DynamicArtifactProps {
  code?: string;
  filePath?: string;
  className?: string;
}

export const DynamicArtifact: React.FC<DynamicArtifactProps> = ({ code, filePath, className }) => {
  const [content, setContent] = useState<string>(code || '');
  const [error, setError] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(!code && !!filePath);

  useEffect(() => {
    if (filePath && !code) {
      const loadContent = async () => {
        try {
          setIsLoading(true);
          // Load file content if not provided directly
          const fileContent = await window.fs.readFile(filePath, { encoding: 'utf8' });
          setContent(fileContent as string);
          setError(null);
        } catch (err) {
          console.error('Error loading file:', err);
          setError(`Failed to load file: ${err instanceof Error ? err.message : String(err)}`);
        } finally {
          setIsLoading(false);
        }
      };

      loadContent();
    }
  }, [filePath, code]);

  if (isLoading) {
    return <div className="animate-pulse p-4">Loading component...</div>;
  }

  if (error) {
    return (
      <div className="bg-red-100 p-4 rounded border border-red-400 text-red-700">
        <h3 className="font-bold">Error</h3>
        <pre className="mt-2 overflow-auto max-h-64">{error}</pre>
      </div>
    );
  }

  // For now, just display the code - we'll improve this in next steps
  return (
    <div className={className}>
      <div className="p-4">
        <pre className="bg-gray-800 text-white p-4 rounded overflow-auto max-h-[600px]">
          <code>{content}</code>
        </pre>
      </div>
    </div>
  );
};

